class Solution {
    public int numberOfWays(int n, int x) {
        int MOD = 1000000007;
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j * j <= i; j++) {
                if (i - j * j >= 0) {
                    dp[i] = (dp[i] + dp[i - j * j]) % MOD;
                }
            }
        }
        return dp[n];
    }
}
